import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getAllPurchaseRequests, approvePurchaseRequest, rejectPurchaseRequest } from '../../services/dataService';
import { formatDate, formatCurrency } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';
import { FiEye, FiCheck, FiX, FiFilter } from 'react-icons/fi';

const AdminPurchaseRequests = () => {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [actionModal, setActionModal] = useState({ show: false, request: null, action: '' });
  const [adminNotes, setAdminNotes] = useState('');
  const [actionLoading, setActionLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => { fetchRequests(); }, []);

  const fetchRequests = async () => {
    try {
      setLoading(true);
      const res = await getAllPurchaseRequests();
      setRequests(res.data.data || []);
      setError('');
    } catch (err) { 
      console.error('Error fetching requests:', err);
      setError('Failed to fetch requests');
    }
    finally { setLoading(false); }
  };

  const handleAction = async () => {
    if (!actionModal.request) return;
    
    setActionLoading(true);
    try {
      const payload = { adminNotes: adminNotes || '' };
      
      if (actionModal.action === 'approved') {
        await approvePurchaseRequest(actionModal.request._id, payload);
      } else if (actionModal.action === 'rejected') {
        await rejectPurchaseRequest(actionModal.request._id, payload);
      }
      
      setActionModal({ show: false, request: null, action: '' });
      setAdminNotes('');
      setError('');
      fetchRequests();
    } catch (err) { 
      console.error('Error updating request:', err);
      setError(err.response?.data?.message || 'Failed to update request');
    }
    finally { setActionLoading(false); }
  };

  const filtered = filter === 'all' ? requests : requests.filter(r => r.status === filter);

  if (loading) return <LoadingSpinner />;

  const counts = {
    all: requests.length,
    pending: requests.filter(r => r.status === 'pending').length,
    approved: requests.filter(r => r.status === 'approved').length,
    rejected: requests.filter(r => r.status === 'rejected').length
  };

  return (
    <div>
      <div className="page-header">
        <div>
          <h1>Purchase Requests</h1>
          <p className="subtitle">Manage customer purchase requests and approvals</p>
        </div>
      </div>

      {error && <div className="alert alert-danger" style={{ marginBottom: '16px' }}>{error}</div>}

      <div className="filters-bar" style={{ marginBottom: '24px', display: 'flex', gap: '8px', alignItems: 'center' }}>
        <FiFilter style={{ color: '#666' }} />
        {['all', 'pending', 'approved', 'rejected'].map(f => (
          <button 
            key={f} 
            className={`btn btn-sm ${filter === f ? 'btn-primary' : 'btn-outline'}`} 
            onClick={() => setFilter(f)}
            style={{ whiteSpace: 'nowrap' }}
          >
            <strong>{f === 'all' ? 'All' : f.charAt(0).toUpperCase() + f.slice(1)}</strong> ({counts[f]})
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div className="card" style={{ textAlign: 'center', padding: '40px 20px' }}>
          <p style={{ color: '#666', fontSize: '16px' }}>No purchase requests found</p>
        </div>
      ) : (
        <div className="table-container">
          <table className="table">
            <thead>
              <tr>
                <th>Property</th>
                <th>Customer</th>
                <th>Email</th>
                <th>Phone</th>
                <th>Status</th>
                <th>Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(req => (
                <tr key={req._id}>
                  <td>
                    <strong>{req.property?.title || 'N/A'}</strong>
                    <br />
                    <small style={{ color: '#5f6368' }}>₹{formatCurrency(req.property?.price)}</small>
                  </td>
                  <td>{req.customerName || 'Unknown'}</td>
                  <td>{req.customerEmail || '-'}</td>
                  <td>{req.customerPhone || '-'}</td>
                  <td><StatusBadge status={req.status} /></td>
                  <td>{formatDate(req.createdAt)}</td>
                  <td>
                    <div className="btn-group" style={{ display: 'flex', gap: '4px' }}>
                      <Link 
                        to={`/admin/purchase-requests/${req._id}`} 
                        className="btn btn-sm btn-info"
                        title="View Details"
                      >
                        <FiEye />
                      </Link>
                      {req.status === 'pending' && (
                        <>
                          <button 
                            className="btn btn-sm btn-success"
                            onClick={() => setActionModal({ show: true, request: req, action: 'approved' })}
                            title="Approve Request"
                          >
                            <FiCheck />
                          </button>
                          <button 
                            className="btn btn-sm btn-danger"
                            onClick={() => setActionModal({ show: true, request: req, action: 'rejected' })}
                            title="Reject Request"
                          >
                            <FiX />
                          </button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {actionModal.show && (
        <ConfirmModal
          show={actionModal.show}
          title={`${actionModal.action === 'approved' ? 'Approve' : 'Reject'} Purchase Request`}
          message={
            <div>
              <p style={{ marginBottom: '12px' }}>
                Are you sure you want to <strong>{actionModal.action === 'approved' ? 'approve' : 'reject'}</strong> this purchase request?
              </p>
              <div style={{ 
                backgroundColor: '#f5f5f5', 
                padding: '12px', 
                borderRadius: '4px', 
                marginBottom: '16px',
                fontSize: '14px'
              }}>
                <strong>Property:</strong> {actionModal.request?.property?.title} <br />
                <strong>Customer:</strong> {actionModal.request?.customerName} <br />
                <strong>Email:</strong> {actionModal.request?.customerEmail}
              </div>
              <div className="form-group">
                <label style={{ fontWeight: '500' }}>Admin Notes (Optional)</label>
                <textarea 
                  className="form-control" 
                  value={adminNotes} 
                  onChange={(e) => setAdminNotes(e.target.value)} 
                  rows="3" 
                  placeholder="Add notes about this decision..."
                  disabled={actionLoading}
                />
              </div>
            </div>
          }
          onConfirm={handleAction}
          onCancel={() => { 
            setActionModal({ show: false, request: null, action: '' }); 
            setAdminNotes(''); 
          }}
          confirmText={actionLoading ? 'Processing...' : (actionModal.action === 'approved' ? 'Approve' : 'Reject')}
          danger={actionModal.action === 'rejected'}
          disabled={actionLoading}
        />
      )}
    </div>
  );
};

export default AdminPurchaseRequests;
